<script setup lang="ts">import AppModal from './AppModal.vue';import AppButton from './AppButton.vue';defineProps<{show:boolean;title:string;message:string}>();defineEmits<{(e:'confirm'):void;(e:'cancel'):void}>();</script><template><AppModal :show="show" :title="title" @close="$emit('cancel')"><p class="text-sm text-slate-600">{{message}}</p><div class="mt-6 flex justify-end gap-2"><AppButton variant="secondary" @click="$emit('cancel')">Batal</AppButton><AppButton variant="danger" @click="$emit('confirm')">Konfirmasi</AppButton></div></AppModal></template>
